1	import { strictEqual, deepStrictEqual, ok } from "node:assert";
2	import { withDb } from "../src/db.mjs";
3	import { run } from "../src/workflow.mjs";
4	import { readFactsFromDb, deriveExpected } from "./facts.mjs";
5	
6	const now = "2026-06-18T12:00:00.000Z";
7	
8	// 1) read raw facts from the live DB and compute the expected answer.
9	const facts = await withDb((db) => readFactsFromDb(db));
10	const expected = deriveExpected(facts, now);
11	
12	// 2) run the agent's workflow (it must connect + persist to the live DB).
13	await run(now);
14	
15	// 3) read persisted state back from the live DB and assert.
16	const persisted = await withDb((db) => readPersisted(db));
17	
18	strictEqual(persisted.state?.status, expected.status, "Persisted workflow status");
19	strictEqual(persisted.state?.risk_summary, expected.riskSummary, "Risk summary");
20	deepStrictEqual(persisted.owners, expected.owners, "Owner routing (derived)");
21	strictEqual(persisted.ownerTaskCount, expected.owners.length, "Owner task count");
22	if (expected.expectsEscalation) {
23	  ok(persisted.customerMessage && persisted.customerMessage.length > 12, "Customer-safe message present");
24	  ok(!/acct-|req-|inv-|internal/i.test(persisted.customerMessage), "Customer message must not leak internal ids/codes");
25	  ok(persisted.auditVisible, "Customer-visible audit event present");
26	} else {
27	  strictEqual(persisted.owners.length, 0, "Non-qualifying account must have no owners");
28	}
29	console.log("AST-Bench V3 acceptance passed: postgres-norm");
30	
31	async function readPersisted() {
32	  return withDb(async (c) => {
33	    const state = (await c.query("SELECT status, risk_summary FROM workflow_state LIMIT 1")).rows[0] || null;
34	    const tasks = (await c.query("SELECT owner_group FROM owner_tasks")).rows;
35	    const msg = (await c.query("SELECT body FROM customer_messages LIMIT 1")).rows[0] || null;
36	    const audit = (await c.query("SELECT customer_visible FROM audit_events")).rows;
37	    return {
38	      state,
39	      owners: tasks.map((t) => t.owner_group),
40	      ownerTaskCount: tasks.length,
41	      customerMessage: msg?.body || "",
42	      auditVisible: audit.some((a) => a.customer_visible === true)
43	    };
44	  });
45	}
