    const acct = (await client.query("SELECT * FROM accounts LIMIT 1")).rows[0];

    const invoices = (await client.query(
      "SELECT invoice_id, amount_cents, due_date, status FROM invoices WHERE account_id = $1",
      [acct.account_id]
    )).rows;

    const shipments = (await client.query(
      "SELECT shipment_id, sla_date, delivered_date, status FROM shipments WHERE account_id = $1",
      [acct.account_id]
    )).rows;

    const regulatoryFlags = (await client.query(
      "SELECT flag_id, type, status FROM regulatory_flags WHERE account_id = $1",
      [acct.account_id]
    )).rows;

    const supportCases = (await client.query(
      "SELECT case_id, severity, status FROM support_cases WHERE account_id = $1",
      [acct.account_id]
    )).rows;

    const usageRow = (await client.query(
      "SELECT prior_period_units, current_period_units FROM usage_periods WHERE account_id = $1 LIMIT 1",
      [acct.account_id]
    )).rows[0];

    const reqRow = (await client.query(
      "SELECT request_id FROM workflow_requests WHERE account_id = $1 LIMIT 1",
      [acct.account_id]
    )).rows[0];
    const requestId = reqRow?.request_id ?? randomUUID();

    const qualifyingTiers = ["strategic", "enterprise"];
    const tierQualifies = qualifyingTiers.includes(acct.tier?.toLowerCase());

    const signals = [];

    const hasRegulatoryHold = regulatoryFlags.some((f) => f.status === "open");
    if (hasRegulatoryHold) signals.push("Regulatory hold");

    const hasOverdueInvoice = invoices.some((i) => {
      return i.status !== "paid" && new Date(i.due_date) < nowDate && Number(i.amount_cents) >= 2500000;
    });
    if (hasOverdueInvoice) signals.push("Overdue invoice");

    const hasDelayedShipment = shipments.some((s) => {
      return !s.delivered_date && new Date(s.sla_date) < nowDate;
    });
    if (hasDelayedShipment) signals.push("Delayed shipment");

    const hasEscalatedSupport = supportCases.some((s) => {
      return s.status === "open" && ["high", "critical"].includes(s.severity?.toLowerCase());
    });
    if (hasEscalatedSupport) signals.push("Escalated support");

    if (usageRow) {
      const prior = Number(usageRow.prior_period_units);
      const current = Number(usageRow.current_period_units);
      if (prior > 0 && current <= prior * 0.7) signals.push("Usage decline");
    }

    const escalating = tierQualifies && signals.length > 0;

    const status = escalating
      ? "At-risk escalation active with executive recovery owner routing and customer-visible audit history."
      : "Monitoring — no escalation required.";

    const owners = [];
    if (escalating) {
      if (signals.includes("Regulatory hold")) owners.push("Legal");
      if (signals.includes("Overdue invoice")) owners.push("Finance");
      if (signals.includes("Delayed shipment") || signals.includes("Usage decline")) owners.push("Customer Success");
      if (signals.includes("Escalated support")) owners.push("Support");
    }

    const riskSummary = `${signals.length} signals: ${signals.join(", ")}`;

    const topOwner = owners[0] ?? "";
    const nextStep = escalating
      ? `${topOwner} recovery review by 16:00`
      : "Continue standard monitoring.";

    await client.query("DELETE FROM workflow_state WHERE account_id = $1", [acct.account_id]);
    await client.query("DELETE FROM owner_tasks WHERE account_id = $1", [acct.account_id]);
    await client.query("DELETE FROM customer_messages WHERE account_id = $1", [acct.account_id]);
    await client.query("DELETE FROM audit_events WHERE account_id = $1", [acct.account_id]);

    await client.query(
      "INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary) VALUES ($1, $2, $3, $4, $5, $6)",
      [requestId, acct.account_id, "Strategic Account Rescue", status, nextStep, riskSummary]
    );

    const dueAt = new Date(nowDate.getTime() + 24 * 60 * 60 * 1000).toISOString();
    for (const owner of owners) {
      await client.query(
        "INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1, $2, $3, $4, $5, $6)",
        [requestId, acct.account_id, owner, `${owner} recovery review for ${acct.name}`, dueAt, "open"]
      );
    }

    const customerBody = escalating
      ? `We are actively monitoring your account and have identified ${signals.length} area${signals.length > 1 ? "s" : ""} requiring immediate attention. Our dedicated recovery team has been engaged to address these concerns and ensure your business continuity. A senior representative will be in contact with you shortly to discuss next steps and provide a resolution timeline.`
      : `Your account is in good standing and is being monitored through our standard processes. No immediate action is required at this time. Please reach out if you have any questions or concerns.`;

    await client.query(
      "INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)",
      [requestId, acct.account_id, customerBody]
    );

    const eventDescription = escalating
      ? `Account escalation workflow initiated. ${signals.length} risk signal${signals.length > 1 ? "s" : ""} detected: ${signals.join(", ")}. Recovery owners assigned.`
      : "Standard monitoring workflow initiated. No escalation required.";

    await client.query(
      "INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible) VALUES ($1, $2, $3, $4, $5)",
      [requestId, acct.account_id, eventDescription, nowDate.toISOString(), true]
    );
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}
